#include <iostream>
using namespace std;

int main() {
    int x = 42;

    // Pointer: stores address of x
    int* ptr = &x;       // & = 'address of'
    cout << ptr;         // memory address (e.g., 0x7fff...)
    cout << *ptr;        // 42 — * dereferences (reads value at address)

    *ptr = 100;          // modify x through the pointer
    cout << x;           // 100

    // Null pointer
    int* null_ptr = nullptr;  // use nullptr (not NULL or 0)
    if (null_ptr == nullptr) cout << "null\n";

    // Reference: alias for x
    int& ref = x;        // must initialize immediately
    ref = 200;           // modifies x directly
    cout << x;           // 200
    // int& bad_ref;     // ERROR: reference must be initialized
    // ref = y;          // this ASSIGNS 200 to y, does NOT reseat ref

    // Pointer arithmetic
    int arr[] = {10, 20, 30, 40, 50};
    int* p = arr;        // points to arr[0]
    cout << *p;          // 10
    p++;                 // advance by sizeof(int) bytes
    cout << *p;          // 20
    cout << *(p + 2);    // 40 (arr[3])

    // const correctness
    const int* cptr = &x;   // can't modify *cptr
    int* const ptrc = &x;   // can't change where ptrc points
    const int* const both = &x;  // neither

    // Pointer to pointer
    int** pptr = &ptr;
    cout << **pptr;      // 200
    return 0;
}

