void stack_vs_heap() {
    // STACK: automatic, fast, limited (~1-8MB)
    int x = 10;           // allocated on stack
    int arr[100];         // 400 bytes on stack
    // When function returns, x and arr are automatically freed

    // HEAP: manual, unlimited (RAM limit)
    int* p = new int(42);     // allocate one int on heap
    int* arr2 = new int[100]; // allocate array on heap

    cout << *p << "\n";       // 42

    delete p;       // MUST delete to avoid memory leak
    delete[] arr2;  // MUST use delete[] for arrays
    p = nullptr;    // good practice: null after delete
}

