#include <iostream>
#include <string>
using namespace std;

class BankAccount {
private:                          // default for class
    string owner_;
    double balance_;
    const int account_id_;        // const — must use init list

public:
    // Constructor with member initialization list
    BankAccount(const string& owner, double balance, int id)
        : owner_(owner),          // init list (before body)
          balance_(balance),
          account_id_(id)         // const member MUST be in init list
    {
        cout << "Account created for " << owner_ << "\n";
    }

    // Copy constructor
    BankAccount(const BankAccount& other)
        : owner_(other.owner_),
          balance_(other.balance_),
          account_id_(other.account_id_) {}

    // Destructor
    ~BankAccount() {
        cout << "Account closed for " << owner_ << "\n";
    }

    // Member functions
    void deposit(double amount) {
        if (amount <= 0) throw invalid_argument("Amount must be positive");
        balance_ += amount;
    }

    double getBalance() const {   // 'const' method: doesn't modify object
        return balance_;
    }

    // Static method: no 'this' pointer
    static string getBankName() { return "C++ Bank"; }

    // Friend function: can access private members
    friend ostream& operator<<(ostream& os, const BankAccount& acc) {
        return os << acc.owner_ << ": $" << acc.balance_;
    }
};

int main() {
    BankAccount acc("Alice", 1000.0, 42);
    acc.deposit(500.0);
    cout << acc.getBalance() << "\n";  // 1500
    cout << acc << "\n";               // Alice: $1500 (operator<<)
    cout << BankAccount::getBankName() << "\n";  // static method
    // acc automatically destroyed when main() exits
    return 0;
}

