// Abstract base class
class Shape {
public:
    // Pure virtual: MUST be overridden, class is abstract
    virtual double area() const = 0;
    virtual double perimeter() const = 0;

    // Virtual method with default implementation
    virtual void describe() const {
        cout << typeid(*this).name() << " area=" << area() << "\n";
    }

    // CRITICAL: virtual destructor
    virtual ~Shape() = default;  // without this, derived destructor not called!
};

class Circle : public Shape {
    double radius_;
public:
    explicit Circle(double r) : radius_(r) {}
    double area()      const override { return 3.14159 * radius_ * radius_; }
    double perimeter() const override { return 2 * 3.14159 * radius_; }
};

class Rectangle : public Shape {
    double w_, h_;
public:
    Rectangle(double w, double h) : w_(w), h_(h) {}
    double area()      const override { return w_ * h_; }
    double perimeter() const override { return 2 * (w_ + h_); }
};

// Polymorphism: base pointer, derived object
void printArea(const Shape& s) {  // reference to base
    cout << s.area() << "\n";      // virtual dispatch at runtime
}

