#include <vector>
#include <list>
#include <map>
#include <unordered_map>
#include <set>
#include <deque>
#include <stack>
#include <queue>
#include <iostream>
using namespace std;

int main() {
    // vector: O(1) random access, O(N) insert middle, amortized O(1) push_back
    vector<int> v = {3, 1, 4, 1, 5};
    v.push_back(9);           // append
    v.reserve(100);           // pre-allocate to avoid reallocation
    cout << v[2];             // 4 — O(1) random access
    v.insert(v.begin(), 0);   // O(N) — shifts all elements

    // list: O(1) insert/erase anywhere (with iterator), O(N) find
    list<int> lst = {1, 2, 3};
    auto it = lst.begin();
    advance(it, 1);           // O(N) to reach position
    lst.insert(it, 99);       // O(1) insert at iterator
    lst.remove(2);            // remove all elements == 2

    // map: sorted by key (Red-Black tree), O(log N)
    map<string, int> scores;
    scores["Alice"] = 95;
    scores["Bob"]   = 80;
    scores.count("Alice");   // 1 (exists)
    for (auto& [key, val] : scores)  // structured bindings (C++17)
        cout << key << ": " << val << "\n";
    // Output sorted: Alice: 95, Bob: 80

    // unordered_map: O(1) average, no order guarantee
    unordered_map<string, int> umap;
    umap["x"] = 10;
    umap.find("x") != umap.end();  // key exists check
    umap.at("x");                   // throws out_of_range if absent

    // set: unique sorted elements
    set<int> s = {5, 3, 1, 3, 5};
    // s = {1, 3, 5} — duplicates removed, sorted
    s.insert(2);
    s.erase(3);
    s.count(5);  // 1 or 0

    // deque: O(1) push/pop at both ends
    deque<int> dq;
    dq.push_front(1);  // O(1) — unlike vector
    dq.push_back(2);
    dq.pop_front();    // O(1)

    // stack (LIFO) and queue (FIFO) adapters
    stack<int> stk;
    stk.push(1); stk.push(2);
    stk.top();   // 2 (peek)
    stk.pop();   // removes 2

    priority_queue<int> pq;  // max-heap
    pq.push(3); pq.push(1); pq.push(5);
    pq.top();    // 5 (max)
    return 0;
}

