using namespace std;

int main() {
    vector<int> v = {5, 2, 8, 1, 9, 3, 7, 4, 6};

    // sort: O(N log N) introsort
    sort(v.begin(), v.end());                          // ascending
    sort(v.begin(), v.end(), greater<int>());           // descending
    sort(v.begin(), v.end(), [](int a, int b) {        // custom comparator
        return abs(a) < abs(b);
    });

    // find: linear search O(N)
    auto it = find(v.begin(), v.end(), 5);
    if (it != v.end()) cout << "Found at: " << distance(v.begin(), it) << "\n";

    // find_if: find with predicate
    auto even_it = find_if(v.begin(), v.end(), [](int x) { return x % 2 == 0; });

    // count_if: count matching elements
    int evens = count_if(v.begin(), v.end(), [](int x) { return x % 2 == 0; });

    // transform: apply function to each element (map)
    vector<int> squares(v.size());
    transform(v.begin(), v.end(), squares.begin(), [](int x) { return x * x; });

    // accumulate: fold/reduce
    int sum     = accumulate(v.begin(), v.end(), 0);          // 45
    int product = accumulate(v.begin(), v.end(), 1,
                             [](int acc, int x) { return acc * x; });

    // remove_if + erase idiom (erase-remove idiom)
    v.erase(remove_if(v.begin(), v.end(), [](int x) { return x % 2 == 0; }),
            v.end());
    // v now contains only odd numbers

    // Binary search (requires sorted range)
    vector<int> sorted = {1, 3, 5, 7, 9};
    bool found  = binary_search(sorted.begin(), sorted.end(), 5); // true
    auto lb     = lower_bound(sorted.begin(), sorted.end(), 5);   // iterator to 5
    auto ub     = upper_bound(sorted.begin(), sorted.end(), 5);   // iterator past 5

    // partition: reorder so predicate is true for all elements before partition
    partition(v.begin(), v.end(), [](int x) { return x % 2 == 0; });

    // min/max element
    auto minIt = min_element(v.begin(), v.end());
    auto maxIt = max_element(v.begin(), v.end());
    cout << *minIt << " " << *maxIt << "\n";

    // C++20 Ranges (more ergonomic)
    // ranges::sort(v);  // no need for begin/end
    return 0;
}

#include <memory>
#include <iostream>
using namespace std;

struct Resource {
    int id;
    Resource(int i) : id(i) { cout << "Resource " << id << " created\n"; }
    ~Resource() { cout << "Resource " << id << " destroyed\n"; }
};

void unique_ptr_demo() {
    // unique_ptr: single owner
    auto p1 = make_unique<Resource>(1);  // preferred over: unique_ptr<Resource>(new Resource(1))
    p1->id;           // access member via ->
    (*p1).id;         // or dereference
    p1.get();         // raw pointer (don't store it long-term)

    // Transfer ownership with std::move
    auto p2 = move(p1);  // p1 is now null, p2 owns the resource
    // p1;  // nullptr now — p1 released ownership
    // p2 destroyed at end of scope -> Resource 1 destroyed
}

void shared_ptr_demo() {
    auto sp1 = make_shared<Resource>(2);  // ref count = 1
    {
        auto sp2 = sp1;           // ref count = 2
        cout << sp1.use_count() << "\n";  // 2
    }  // sp2 destroyed -> ref count = 1
    cout << sp1.use_count() << "\n";  // 1
}   // sp1 destroyed -> ref count = 0 -> Resource 2 destroyed

void weak_ptr_demo() {
    auto sp = make_shared<Resource>(3);
    weak_ptr<Resource> wp = sp;  // doesn't increment ref count

    cout << sp.use_count() << "\n";  // 1 (weak_ptr doesn't count)

    // Access via lock() — returns shared_ptr if still alive
    if (auto locked = wp.lock()) {
        locked->id;  // safe to use
    } else {
        cout << "Resource already destroyed\n";
    }

    sp.reset();  // Resource 3 destroyed here
    auto dead = wp.lock();  // returns nullptr — object is gone
}

// Circular reference problem and solution
struct Node {
    shared_ptr<Node> next;  // BAD: circular ref prevents deallocation
    weak_ptr<Node>   next_w; // GOOD: weak_ptr breaks the cycle
    ~Node() { cout << "Node destroyed\n"; }
};

int main() {
    unique_ptr_demo();  // Resource 1 destroyed
    shared_ptr_demo();  // Resource 2 destroyed
    weak_ptr_demo();    // Resource 3 destroyed
    return 0;
}

