#include <iostream>
#include <vector>
#include <string>
#include <utility>  // std::move, std::forward
using namespace std;

class Buffer {
    int* data_;
    size_t size_;
public:
    // Constructor
    Buffer(size_t n) : size_(n), data_(new int[n]) {
        cout << "Allocated " << n << "\n";
    }

    // Copy constructor: expensive O(N) deep copy
    Buffer(const Buffer& other) : size_(other.size_), data_(new int[other.size_]) {
        copy(other.data_, other.data_ + other.size_, data_);
        cout << "Copied " << size_ << "\n";
    }

    // Move constructor: O(1) — steal resources
    Buffer(Buffer&& other) noexcept
        : size_(other.size_), data_(other.data_) {  // take other's pointer
        other.data_ = nullptr;  // leave other in valid-but-empty state
        other.size_ = 0;
        cout << "Moved " << size_ << "\n";
    }

    // Move assignment operator
    Buffer& operator=(Buffer&& other) noexcept {
        if (this != &other) {
            delete[] data_;         // free existing resources
            data_ = other.data_;    // steal
            size_ = other.size_;
            other.data_ = nullptr;  // null out source
            other.size_ = 0;
        }
        return *this;
    }

    ~Buffer() { delete[] data_; }
};

Buffer createBuffer() {
    Buffer b(1000);  // local variable
    return b;        // RVO/NRVO: may not even call move constructor!
}

int main() {
    Buffer b1(100);          // Allocated 100
    Buffer b2(b1);           // Copied 100 (expensive)
    Buffer b3(move(b1));     // Moved 100 (cheap — b1 is now empty)
    // b1 is now valid but unspecified (nullptr, size 0)

    // std::move with containers
    string s = "Hello, World!";
    vector<string> v;
    v.push_back(move(s));    // s's internal buffer moved into vector
    cout << s.empty() << "\n";  // likely true — s was moved from

    // Perfect forwarding (template function)
    template <typename T>
    void wrapper(T&& arg) {
        process(forward<T>(arg));  // preserves lvalue/rvalue-ness
    }
    return 0;
}

