// Shared counter with mutex protection
class ThreadSafeCounter {
    int count_ = 0;
    mutex mtx_;
public:
    void increment() {
        lock_guard<mutex> lock(mtx_);  // RAII: auto-unlocks
        count_++;
    }  // lock released here

    int get() {
        lock_guard<mutex> lock(mtx_);
        return count_;
    }
};

void threadBasics() {
    ThreadSafeCounter counter;

    vector<thread> threads;
    for (int i = 0; i < 10; i++) {
        threads.emplace_back([&counter]() {
            for (int j = 0; j < 1000; j++) counter.increment();
        });
    }
    for (auto& t : threads) t.join();  // wait for all threads
    cout << counter.get() << "\n";  // 10000
}

// Condition variable: producer-consumer
mutex mtx;
condition_variable cv;
bool ready = false;
int shared_data = 0;

void producer() {
    shared_data = 42;
    {
        lock_guard<mutex> lock(mtx);
        ready = true;
    }
    cv.notify_one();  // wake up one waiting thread
}

void consumer() {
    unique_lock<mutex> lock(mtx);
    cv.wait(lock, [] { return ready; });  // wait until ready is true
    cout << "Got: " << shared_data << "\n";  // 42
}

// std::async: high-level task parallelism
long heavy_task(int n) {
    long sum = 0;
    for (int i = 0; i < n; i++) sum += i;
    return sum;
}

void asyncDemo() {
    // Launch async task (may run in new thread or deferred)
    auto f1 = async(launch::async, heavy_task, 1'000'000);
    auto f2 = async(launch::async, heavy_task, 2'000'000);

    // Do other work while tasks run...

    long r1 = f1.get();  // blocks until f1 is done
    long r2 = f2.get();
    cout << r1 + r2 << "\n";
}

int main() {
    thread t1(producer);
    thread t2(consumer);
    t1.join();
    t2.join();
    asyncDemo();
    return 0;
}
